commands.cmd:
ps_out=$(ps axo stat=,pid=,comm=) || { echo "ps failed" >&2; exit 1; }
printf '%s\n' "$ps_out" | awk '
  $1 ~ /^Z/ {
    c=$3; gsub(/\\/,"\\\\",c); gsub(/"/,"\\\"",c)
    if (n>0) sep=","; else sep="";
    list = list sep "{\"pid\":" $2 ",\"comm\":\"" c "\"}";
    n++
  }
  END{
    printf "{\"zombie_count\":%d,\"results\":[%s]}", n, list
  }' || exit 1
